import re

def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    # Define the regex pattern for the allowed SQL syntax
    pattern = r"^\s*SELECT\s+(?P<columns>\*|[\w\s,]+)\s+FROM\s+rows\s*(WHERE\s+(?P<where_col>\w+)\s*(?P<op>=|<|>|<=|>=|!=)\s*(?P<where_val>-?\d+))?\s*(LIMIT\s+(?P<limit>\d+))?\s*$"

    # Check for forbidden keywords
    forbidden_keywords = ["DELETE", "UPDATE", "INSERT", "DROP", "ALTER", "CREATE", "PRAGMA", ";"]
    for keyword in forbidden_keywords:
        if keyword in query.upper():
            raise ValueError("Query contains forbidden SQL keywords.")

    # Match the query against the allowed pattern
    match = re.match(pattern, query, re.IGNORECASE)
    if not match:
        raise ValueError("Query does not match the allowed SELECT syntax.")

    # Extract components from the query
    columns = match.group("columns").strip()
    where_col = match.group("where_col")
    op = match.group("op")
    where_val = match.group("where_val")
    limit = match.group("limit")

    # Validate column names
    if columns != "*":
        selected_columns = [col.strip() for col in columns.split(",")]
        for col in selected_columns:
            if col not in rows[0]:
                raise ValueError(f"Unknown column: {col}")
    else:
        selected_columns = list(rows[0].keys())

    # Validate WHERE clause column
    if where_col and where_col not in rows[0]:
        raise ValueError(f"Unknown column in WHERE clause: {where_col}")

    # Filter rows based on WHERE clause
    if where_col:
        where_val = int(where_val)
        if op == "=":
            filtered_rows = [row for row in rows if row[where_col] == where_val]
        elif op == "<":
            filtered_rows = [row for row in rows if row[where_col] < where_val]
        elif op == ">":
            filtered_rows = [row for row in rows if row[where_col] > where_val]
        elif op == "<=":
            filtered_rows = [row for row in rows if row[where_col] <= where_val]
        elif op == ">=":
            filtered_rows = [row for row in rows if row[where_col] >= where_val]
        elif op == "!=":
            filtered_rows = [row for row in rows if row[where_col] != where_val]
    else:
        filtered_rows = rows

    # Apply LIMIT if specified
    if limit:
        limit = int(limit)
        filtered_rows = filtered_rows[:limit]

    # Select the specified columns
    result = [{col: row[col] for col in selected_columns} for row in filtered_rows]

    return result

